import{_ as a,a as t}from"./chunks/填写github渠道配置.B-S0-llS.js";import{_ as r,o,c as i,a2 as s}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"Añadir un canal GitHub Releases","description":"","frontmatter":{},"headers":[],"relativePath":"es/upload/github-releases.md","filePath":"es/upload/github-releases.md","lastUpdated":1781962217000}'),l={name:"es/upload/github-releases.md"};function d(n,e,u,c,p,b){return o(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="anadir-un-canal-github-releases" tabindex="-1">Añadir un canal GitHub Releases <a class="header-anchor" href="#anadir-un-canal-github-releases" aria-label="Permalink to &quot;Añadir un canal GitHub Releases&quot;">​</a></h1><p>El canal GitHub Releases guarda archivos como Release Assets en un repositorio de GitHub.</p><h2 id="cuando-conviene" tabindex="-1">Cuándo conviene <a class="header-anchor" href="#cuando-conviene" aria-label="Permalink to &quot;Cuándo conviene&quot;">​</a></h2><ul><li>Ya usas GitHub con frecuencia.</li><li>Quieres guardar archivos pequeños o recursos de distribución en Releases.</li><li>Prefieres un destino gestionado con GitHub Token.</li></ul><h2 id="que-preparar" tabindex="-1">Qué preparar <a class="header-anchor" href="#que-preparar" aria-label="Permalink to &quot;Qué preparar&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requisito</th><th>Uso</th></tr></thead><tbody><tr><td>Cuenta de GitHub</td><td>Gestionar repositorio y token</td></tr><tr><td>Repositorio</td><td>Lugar donde estarán los Releases</td></tr><tr><td>Personal Access Token</td><td>Subir assets al Release</td></tr><tr><td>Release Tag</td><td>Release al que se asociarán los archivos</td></tr></tbody></table><h2 id="permisos-del-token" tabindex="-1">Permisos del token <a class="header-anchor" href="#permisos-del-token" aria-label="Permalink to &quot;Permisos del token&quot;">​</a></h2><p>El Personal Access Token debe poder operar sobre Releases del repositorio objetivo.</p><p><img src="'+a+'" alt="Permisos GitHub" loading="lazy"></p><p>Si el repositorio es privado, añade acceso a repositorios privados.</p><h2 id="rellenar-en-imgbed" tabindex="-1">Rellenar en ImgBed <a class="header-anchor" href="#rellenar-en-imgbed" aria-label="Permalink to &quot;Rellenar en ImgBed&quot;">​</a></h2><p>En Configuración de subida, elige <code>GitHub Releases</code>.</p><table tabindex="0"><thead><tr><th>Campo</th><th>Valor</th></tr></thead><tbody><tr><td>Nombre del canal</td><td>Por ejemplo <code>GitHub Release</code></td></tr><tr><td>Owner</td><td>Propietario del repositorio</td></tr><tr><td>Repo</td><td>Nombre del repositorio</td></tr><tr><td>Token</td><td>Personal Access Token</td></tr><tr><td>Release Tag</td><td>Tag del Release</td></tr><tr><td>Ruta</td><td>Opcional</td></tr></tbody></table><p><img src="'+t+'" alt="Configuración GitHub" loading="lazy"></p><h2 id="verificacion" tabindex="-1">Verificación <a class="header-anchor" href="#verificacion" aria-label="Permalink to &quot;Verificación&quot;">​</a></h2><ol><li>Guarda el canal.</li><li>Sube una imagen de prueba.</li><li>Comprueba que aparece en los Release Assets del repositorio.</li><li>Abre el enlace devuelto por ImgBed.</li></ol><h2 id="notas" tabindex="-1">Notas <a class="header-anchor" href="#notas" aria-label="Permalink to &quot;Notas&quot;">​</a></h2><ul><li>GitHub Releases no es un almacenamiento especializado para grandes volúmenes o tráfico alto.</li><li>Limita el token al repositorio necesario.</li><li>Si borras manualmente assets o releases, los enlaces de ImgBed pueden dejar de funcionar.</li></ul>',18)])])}const f=r(l,[["render",d]]);export{g as __pageData,f as default};
